onClick:
{{
appsmith.store.ultimaOCCreada

?

(
    storeValue(
        "idOCImprimir",
        appsmith.store.ultimaOCCreada
    )

    .then(() => ImprimirOCEncabezado.run())

    .then(() => ImprimirOCDetalle.run())

    .then(async () => {

        await storeValue(
            "ocImpresion",
            ImprimirOCEncabezado.data[0]
        );

        await storeValue(
            "detalleOCImpresion",
            ImprimirOCDetalle.data
        );

        download(
            JS_ImpresionOC.generarHTMLOC(),
            "OC-" +
            String(
                appsmith.store.ultimaOCCreada
            ).padStart(6,"0")
            +
            ".html",
            "text/html"
        );

        showAlert(
            "Orden cargada e impresa correctamente",
            "success"
        );

    })

)

:

showAlert(
    "No existe una OC creada en esta sesión",
    "warning"
)
}}

tooltip:
{{
!appsmith.store.ultimaOCCreada
    ? "No existe una Orden de Compra trabajada en esta sesión"
    : ""
}}
